import{_ as e,o as r,c as l,a2 as t}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F15: 關係人交易與利益輸送風險 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6261_久元/20260512/F15_關係人交易與利益輸送風險.md","filePath":"審計報告庫/財務審計/6261_久元/20260512/F15_關係人交易與利益輸送風險.md"}'),o={name:"審計報告庫/財務審計/6261_久元/20260512/F15_關係人交易與利益輸送風險.md"};function i(n,a,h,s,d,c){return r(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="f15-關係人交易與利益輸送風險-財務審計專家報告" tabindex="-1">F15: 關係人交易與利益輸送風險 - 財務審計專家報告 <a class="header-anchor" href="#f15-關係人交易與利益輸送風險-財務審計專家報告" aria-label="Permalink to &quot;F15: 關係人交易與利益輸送風險 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>是否存在異常大額的關係人交易？其定價是否符合市場行情？是否存在利益輸送或虛增利潤之嫌？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：關係人銷貨4,476萬(1.1%)常規低。宏齊AR 9,342萬(DSO 761天vs一般114天)異常資金佔用。資金貸與2.2億</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：截至2025年關係人交易附註及AR帳齡</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>：關係人銷貨4,476萬(營收1.1%)佔比低無定價疑慮。宏齊AR 9,342萬DSO 761天(vs一般客戶114天)異常超額資金佔用7,945萬。資金貸與YTEC→蘇州久元2.2億(佔現金15.5%)。逾180天AR 9,773萬與宏齊AR高度吻合為集中風險。</li><li><strong>診斷見解</strong>：銷貨規模小無利益輸送疑慮，但關係人收款異常為重大治理瑕疵—單一關係人逾期逾761天隱含無擔保資金貸與未揭露，風險集中於一間公司若違約EPS影響0.48-0.74元。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="規模異常" tabindex="-1">規模異常 <a class="header-anchor" href="#規模異常" aria-label="Permalink to &quot;規模異常&quot;">​</a></h3><p>關係人銷貨4,476萬(營收1.1%)規模小無定價疑慮。<strong>異常在收款：宏齊AR 9,342萬為年銷貨額2.09倍，DSO 761天(一般客戶僅114天)，超額7,945萬實為隱性無擔保資金貸與，若未揭露違反關係人交易揭露規範。</strong> 此類交易引起主管機關關切可能性高，需注意2026年報是否改善。</p><h3 id="ar風險" tabindex="-1">AR風險 <a class="header-anchor" href="#ar風險" aria-label="Permalink to &quot;AR風險&quot;">​</a></h3><p>逾180天AR 9,773萬中宏齊佔96%(9,342萬)，其餘431萬為其他客戶。<strong>已提備抵3,569萬(36.5%)對應預期信用損失，剩餘淨值6,204萬(EPS 0.48元)若實際無法回收將直接侵蝕獲利。</strong> 宏齊與久元同董事長(吳誌雄)，屬實質關係人，回收可能性存在但時間長度已偏離正常商業信用範圍。</p><h3 id="資金貸與" tabindex="-1">資金貸與 <a class="header-anchor" href="#資金貸與" aria-label="Permalink to &quot;資金貸與&quot;">​</a></h3><p>YTEC→蘇州久元2.2億(佔現金15.5%)為集團內部資金調度。上海久析應收2,791萬待回收。<strong>已處分廈門久元但資金貸與仍高，顯示集團整頓未完成。</strong> 若蘇州久元營運改善資金可回收，但若持續虧損資金貸與回收週期將延長。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><h3 id="🔴-空方觀點" tabindex="-1">🔴 空方觀點 <a class="header-anchor" href="#🔴-空方觀點" aria-label="Permalink to &quot;🔴 空方觀點&quot;">​</a></h3><ol><li>宏齊AR DSO 761天非正常商業信用—超額7,945萬等同無擔保無息資金貸與未揭露，透明度不足恐受主管機關關切，治理風險為核心疑慮</li><li>逾180天AR 9,773萬中宏齊佔96%，已提備抵3,569萬但剩餘6,204萬若實際損失EPS影響0.48元，資金佔用壓力集中單一關係人不利分散</li><li>資金貸與2.2億佔現金15.5%，若蘇州久元營運惡化資金回收堪憂</li></ol><h3 id="🟢-多方觀點" tabindex="-1">🟢 多方觀點 <a class="header-anchor" href="#🟢-多方觀點" aria-label="Permalink to &quot;🟢 多方觀點&quot;">​</a></h3><ol><li>關係人銷貨僅1.1%，即使全損AR 9,523萬EPS影響約0.74元不致命</li><li>36.5%高損失率備抵反映會計保守，若最終全額回收將回沖利潤</li><li>集團架構簡化中已處分廈門久元，資金貸與隨整頓降低風險同步下降</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>關係人交易風險集中在宏齊AR而非銷貨規模。9,342萬集中單一關係人逾期&gt;180天為明顯資金佔用疑慮。即使全損EPS影響0.48-0.74元對股價85元不算致命，但治理瑕疵侵蝕投資者信任。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>年報附註：2025 Q4合併財報第73-76頁附註三五(關係人交易)、第34-35頁(AR帳齡分析)</li><li>關係人：宏齊科技(同董事長吳誌雄)</li><li>數據查詢日期：2026-05-12</li></ul>',23)])])}const b=e(o,[["render",i]]);export{u as __pageData,b as default};
